import SwiftUI

struct ContentView: View {
    @EnvironmentObject var walletManager: WalletManager
    @State private var publicKey: String = ""
    @State private var privateKeyAvailable: Bool = false
    @State private var messageToSign: String = ""
    @State private var signature: String = ""
    @State private var transactionStatus: String = ""

    var body: some View {
        VStack(spacing: 20) {
            Button("Generate Key Pair") {
                walletManager.generateKeyPair()
                publicKey = walletManager.getPublicKeyString() ?? "No Public Key"
                privateKeyAvailable = walletManager.hasPrivateKey()
            }
            Text("Public Key: \(publicKey)")

            HStack {
                TextField("Message to sign", text: $messageToSign)
                    .textFieldStyle(RoundedBorderTextFieldStyle())
                Button("Sign") {
                    if let signed = walletManager.signTransaction(messageToSign) {
