            }
            Text("Signature: \(signature)")

            Button("Send Transaction to Blockchain") {
                Task {
                    do {
                        let result = try await BlockchainService.sendTransaction(signature: signature, publicKey: publicKey)
                        transactionStatus = result
                    } catch {
                        transactionStatus = "Error: \(error.localizedDescription)"
                    }
                }
            }
            Text("Status: \(transactionStatus)")
        }
        .padding()
        .onAppear {
            publicKey = walletManager.getPublicKeyString() ?? "No Public Key"
            privateKeyAvailable = walletManager.hasPrivateKey()
        }
    }
}

// WalletManager.swift
import Foundation
import CryptoKit

class WalletManager: ObservableObject {
    private let keychainHelper = KeychainHelper()
    private let privateKeyTag = "com.example.cryptowallet.privateKey"
    private var privateKey: P256.Signing.PrivateKey?

    func generateKeyPair() {
        let newPrivateKey = P256.Signing.PrivateKey()
        privateKey = newPrivateKey
        let privateKeyData = newPrivateKey.rawRepresentation
        keychainHelper.storeKey(privateKeyData, tag: privateKeyTag)
    }

    func hasPrivateKey() -> Bool {
        return keychainHelper.retrieveKey(tag: privateKeyTag) != nil
    }

    func getPublicKeyString() -> String? {
        guard let privateKeyData = keychainHelper.retrieveKey(tag: privateKeyTag),
              let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: privateKeyData) else {
            return nil
        }
        let pubKeyData = privateKey.publicKey.rawRepresentation
        return pubKeyData.base64EncodedString()
    }

    func signTransaction(_ message: String) -> String? {
        guard let privateKeyData = keychainHelper.retrieveKey(tag: privateKeyTag),
              let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: privateKeyData),
              let data = message.data(using: .utf8) else {
            return nil
        }
        do {
            let signature = try privateKey.signature(for: data)
            return signature.derRepresentation.base64EncodedString()
        } catch {
            return nil
        }
    }
}

// KeychainHelper.swift
import Foundation

class KeychainHelper {
    func storeKey(_ keyData: Data, tag: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tag,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlocked
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }

    func retrieveKey(tag: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tag,
            kSecReturnData as String: kCFBooleanTrue as Any,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        if status == errSecSuccess {
            return result as? Data
        }
        return nil
    }
}

// BlockchainService.swift
import Foundation

struct BlockchainService {
    static func sendTransaction(signature: String, publicKey: String) async throws -> String {
        guard let url = URL(string: "https://api.yourblockchainnode.com/transaction") else {
            throw URLError(.badURL)
        }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        let body: [String: Any] = [
            "signature": signature,
            "publicKey": publicKey
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: body, options: [])
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let (data, _) = try await URLSession.shared.data(for: request)
        if let responseString = String(data: data, encoding: .utf8) {
            return responseString
        } else {
            return "Unknown response from blockchain"
        }
    }
}